"use client";

import { useEffect, useState } from "react";
import { useSession } from "next-auth/react";
import Link from "next/link";
import {
  Zap, Target, Flame, Trophy, Clock, BookOpen,
  Timer, Gamepad2, PenLine, TrendingUp, ChevronRight,
  Star, Award, Keyboard, ArrowUpRight, Sparkles,
  BarChart3, RefreshCw, Languages,
} from "lucide-react";
import { useCourse, COURSES, CourseId } from "@/context/CourseContext";
import { useLang } from "@/context/LangContext";
import CourseSelector from "@/components/course/CourseSelector";

// ΓöÇΓöÇ Types ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

interface StatsData {
  totalTests: number;
  bestWpm: number;
  avgWpm: number;
  avgAccuracy: number;
  totalMinutes: number;
  streak: number;
  recentRecords: {
    id: string;
    wpm: number;
    accuracy: number;
    timeSpent: number;
    lessonTitle: string;
    difficulty: string;
    createdAt: string;
  }[];
  wpmHistory: { wpm: number; date: string }[];
  user: { name: string; createdAt: string };
}

// ΓöÇΓöÇ WPM Sparkline ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function WpmSparkline({
  data,
  accentColor,
}: {
  data: { wpm: number }[];
  accentColor: string;
}) {
  if (!data.length) return null;
  const W = 280, H = 72, pad = 6;
  const max   = Math.max(...data.map((d) => d.wpm), 1);
  const min   = Math.min(...data.map((d) => d.wpm), 0);
  const range = max - min || 1;

  const pts = data.map((d, i) => {
    const x = pad + (i / Math.max(data.length - 1, 1)) * (W - pad * 2);
    const y = H - pad - ((d.wpm - min) / range) * (H - pad * 2);
    return `${x},${y}`;
  });

  const areaBottom = `${pts[pts.length - 1].split(",")[0]},${H - pad} ${pad},${H - pad}`;

  return (
    <svg viewBox={`0 0 ${W} ${H}`} className="w-full h-18">
      <defs>
        <linearGradient id="sparkGrad" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%"   stopColor={accentColor} stopOpacity="0.35" />
          <stop offset="100%" stopColor={accentColor} stopOpacity="0"    />
        </linearGradient>
      </defs>
      <polygon points={`${pts.join(" ")} ${areaBottom}`} fill="url(#sparkGrad)" />
      <polyline
        points={pts.join(" ")}
        fill="none"
        stroke={accentColor}
        strokeWidth="2"
        strokeLinejoin="round"
        strokeLinecap="round"
      />
      {pts.map((p, i) => {
        const [x, y] = p.split(",");
        return (
          <circle key={i} cx={x} cy={y} r="3" fill={accentColor} stroke="white" strokeWidth="1.5" />
        );
      })}
    </svg>
  );
}

// ΓöÇΓöÇ Helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function DiffBadge({ diff, lang }: { diff: string; lang: "en" | "bn" }) {
  const styles: Record<string, string> = {
    BEGINNER:     "bg-emerald-500/15 text-emerald-400 border border-emerald-500/25",
    INTERMEDIATE: "bg-amber-500/15 text-amber-400 border border-amber-500/25",
    ADVANCED:     "bg-red-500/15 text-red-400 border border-red-500/25",
  };
  const labelsEn: Record<string, string> = { BEGINNER: "Beginner", INTERMEDIATE: "Intermediate", ADVANCED: "Advanced" };
  const labelsBn: Record<string, string> = { BEGINNER: "αª╢αª┐αªòαºìαª╖αª╛αª¿αª¼αª┐αª╢", INTERMEDIATE: "αª«αªºαºìαª»αª¼αª░αºìαªñαºÇ", ADVANCED: "αªëαª¿αºìαª¿αªñ" };
  const labels = lang === "en" ? labelsEn : labelsBn;
  return (
    <span className={`text-[10px] font-semibold px-2 py-0.5 rounded-full ${styles[diff] ?? "bg-slate-700 text-slate-400"}`}>
      {labels[diff] ?? diff}
    </span>
  );
}

function greeting(lang: "en" | "bn") {
  const h = new Date().getHours();
  if (lang === "en") {
    if (h < 12) return "Good morning"; if (h < 17) return "Good afternoon"; return "Good evening";
  }
  if (h < 12) return "αª╢αºüαª¡ αª╕αªòαª╛αª▓"; if (h < 17) return "αª╢αºüαª¡ αª¼αª┐αªòαºçαª▓"; return "αª╢αºüαª¡ αª╕αª¿αºìαªºαºìαª»αª╛";
}

function timeAgo(dateStr: string, lang: "en" | "bn") {
  const diff = Date.now() - new Date(dateStr).getTime();
  const m = Math.floor(diff / 60000);
  if (lang === "en") {
    if (m < 1) return "just now"; if (m < 60) return `${m}m ago`;
    const h = Math.floor(m / 60); if (h < 24) return `${h}h ago`; return `${Math.floor(h / 24)}d ago`;
  }
  if (m < 1) return "αªÅαªçαª«αª╛αªñαºìαª░"; if (m < 60) return `${m} αª«αª┐αª¿αª┐αªƒ αªåαªùαºç`;
  const h = Math.floor(m / 60); if (h < 24) return `${h} αªÿαªúαºìαªƒαª╛ αªåαªùαºç`; return `${Math.floor(h / 24)} αªªαª┐αª¿ αªåαªùαºç`;
}

// ΓöÇΓöÇ Quick-action sets per course type ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

const NAV_ITEMS_EN = [
  { href: "/practice",   icon: PenLine,  en: "Practice",       bn: "αªàαª¿αºüαª╢αºÇαª▓αª¿",     descEn: "Free typing session",     descBn: "αª«αºüαªòαºìαªñ αªƒαª╛αªçαª¬αª┐αªé",       color: "from-emerald-500 to-teal-500",  shadow: "shadow-emerald-500/20" },
  { href: "/speed-test", icon: Timer,    en: "Speed Test",     bn: "αª╕αºìαª¬αª┐αªí αªƒαºçαª╕αºìαªƒ",  descEn: "Measure WPM & accuracy",  descBn: "WPM αª¬αª░αª┐αª«αª╛αª¬",           color: "from-blue-500 to-cyan-500",     shadow: "shadow-blue-500/20"    },
  { href: "/lessons",    icon: BookOpen, en: "Lessons",        bn: "αª¬αª╛αªá",           descEn: "Structured curriculum",   descBn: "αªòαª╛αªáαª╛αª«αºïαª¼αªªαºìαªº αª¬αª╛αªá",     color: "from-violet-500 to-purple-500", shadow: "shadow-violet-500/20"  },
  { href: "/games",      icon: Gamepad2, en: "Games",          bn: "αªùαºçαª«αª╕",          descEn: "Learn while having fun",  descBn: "αª«αª£αª╛αª░ αªùαºçαª«αª╕",            color: "from-amber-500 to-orange-500",  shadow: "shadow-amber-500/20"   },
];

const NAV_ITEMS_BN = [
  { href: "/lessons",    icon: BookOpen, en: "Bangla Lessons", bn: "αª¼αª╛αªéαª▓αª╛ αª¬αª╛αªá",    descEn: "Structured Bangla path",  descBn: "αª¼αª╛αªéαª▓αª╛ αª¬αª╛αªáαºìαª»αªòαºìαª░αª«",    color: "from-emerald-500 to-teal-500",  shadow: "shadow-emerald-500/20" },
  { href: "/practice",   icon: PenLine,  en: "Practice",       bn: "αªàαª¿αºüαª╢αºÇαª▓αª¿",     descEn: "Free Bangla typing",      descBn: "αª«αºüαªòαºìαªñ αª¼αª╛αªéαª▓αª╛ αªƒαª╛αªçαª¬αª┐αªé", color: "from-violet-500 to-purple-500", shadow: "shadow-violet-500/20"  },
  { href: "/speed-test", icon: Timer,    en: "Speed Test",     bn: "αª╕αºìαª¬αª┐αªí αªƒαºçαª╕αºìαªƒ",  descEn: "Test your Bangla speed",  descBn: "αªùαªñαª┐ αª¬αª░αª┐αª«αª╛αª¬",           color: "from-blue-500 to-cyan-500",     shadow: "shadow-blue-500/20"    },
  { href: "/games",      icon: Gamepad2, en: "Games",          bn: "αªùαºçαª«αª╕",          descEn: "Bangla typing games",     descBn: "αª¼αª╛αªéαª▓αª╛ αªùαºçαª«αª╕",           color: "from-amber-500 to-orange-500",  shadow: "shadow-amber-500/20"   },
];

// ΓöÇΓöÇ Dashboard ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

export default function DashboardPage() {
  const { data: session }             = useSession();
  const { course, clearCourse }       = useCourse();
  const { lang }                      = useLang();
  const [stats,   setStats]           = useState<StatsData | null>(null);
  const [loading, setLoading]         = useState(true);

  useEffect(() => {
    fetch("/api/user/stats")
      .then((r) => r.json())
      .then((d) => { setStats(d); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  // ΓöÇΓöÇ Show course selector if user hasn't chosen yet ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  if (!course) return <CourseSelector />;

  const firstName = (session?.user?.name ?? stats?.user?.name ?? "Learner").split(" ")[0];
  const isEmpty   = !loading && stats?.totalTests === 0;
  const isBangla  = course.id !== "en";
  const navItems  = isBangla ? NAV_ITEMS_BN : NAV_ITEMS_EN;

  const statCards = [
    { label: lang === "en" ? "Best WPM"   : "αª╕αºçαª░αª╛ WPM",       value: loading ? "ΓÇö" : stats?.bestWpm      ?? 0,     icon: Zap,        color: "text-amber-400",   bg: "bg-amber-500/10",   border: "border-amber-500/20"   },
    { label: lang === "en" ? "Avg WPM"    : "αªùαªíαª╝ WPM",         value: loading ? "ΓÇö" : stats?.avgWpm       ?? 0,     icon: TrendingUp, color: "text-blue-400",    bg: "bg-blue-500/10",    border: "border-blue-500/20"    },
    { label: lang === "en" ? "Accuracy"   : "αª¿αª┐αª░αºìαª¡αºüαª▓αªñαª╛",       value: loading ? "ΓÇö" : `${stats?.avgAccuracy ?? 0}%`, icon: Target,     color: course.accentText,  bg: course.accentBg,     border: course.accentBorder     },
    { label: lang === "en" ? "Tests Done" : "αªƒαºçαª╕αºìαªƒ αª╕αª«αºìαª¬αª¿αºìαª¿",  value: loading ? "ΓÇö" : stats?.totalTests   ?? 0,     icon: Trophy,     color: "text-violet-400",  bg: "bg-violet-500/10",  border: "border-violet-500/20"  },
    { label: lang === "en" ? "Minutes"    : "αª«αª┐αª¿αª┐αªƒ",            value: loading ? "ΓÇö" : stats?.totalMinutes ?? 0,     icon: Clock,      color: "text-pink-400",    bg: "bg-pink-500/10",    border: "border-pink-500/20"    },
    { label: lang === "en" ? "Day Streak" : "αªÅαªòαªƒαª╛αª¿αª╛ αªªαª┐αª¿",      value: loading ? "ΓÇö" : stats?.streak       ?? 0,     icon: Flame,      color: "text-orange-400",  bg: "bg-orange-500/10",  border: "border-orange-500/20"  },
  ];

  return (
    <div className="max-w-6xl mx-auto space-y-4">

      {/* ΓöÇΓöÇ Course switch strip ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
      <div className="flex items-center justify-between rounded-xl bg-slate-800/60 border border-slate-700/50 px-4 py-2.5">
        <div className="flex items-center gap-2">
          <Languages className="w-3.5 h-3.5 text-slate-400" />
          <span className="text-xs text-slate-400">
            {lang === "en" ? "Want to learn a different language?" : "αªàαª¿αºìαª» αªòαºïαª░αºìαª╕αºç αª»αºçαªñαºç αªÜαª╛αª¿?"}
          </span>
        </div>
        <button
          onClick={clearCourse}
          className="flex items-center gap-1 text-xs font-semibold text-emerald-400 hover:text-emerald-300 transition-colors"
        >
          <RefreshCw className="w-3 h-3" />
          {lang === "en" ? "Switch course" : "αªòαºïαª░αºìαª╕ αª¬αª░αª┐αª¼αª░αºìαªñαª¿"}
        </button>
      </div>

      {/* ΓöÇΓöÇ Welcome banner ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
      <div
        className={`relative overflow-hidden rounded-2xl border ${course.accentBorder} shadow-xl px-7 py-6`}
        style={{ background: `linear-gradient(135deg, rgb(15 23 42) 0%, rgb(15 23 42 / 0.95) 60%, ${course.accentColor}18 100%)` }}
      >
        <div className="absolute -top-10 -right-10 w-48 h-48 rounded-full blur-3xl pointer-events-none opacity-20" style={{ background: course.accentColor }} />
        <div className="absolute -bottom-6 left-20 w-32 h-32 rounded-full blur-2xl pointer-events-none opacity-10" style={{ background: course.accentColor }} />

        <div className="relative flex items-center justify-between gap-6">
          <div>
            <div className="flex items-center gap-2 mb-2">
              <span className={`text-[10px] font-bold tracking-widest uppercase px-2.5 py-1 rounded-full ${course.accentBg} ${course.accentText} border ${course.accentBorder}`}>
                {course.emoji} {lang === "en" ? course.nameEn : course.nameBn}
              </span>
            </div>
            <div className="flex items-center gap-2 mb-1">
              <Sparkles className={`w-4 h-4 ${course.accentText}`} />
              <span className={`${course.accentText} text-sm font-medium`}>{greeting(lang)}</span>
            </div>
            <h2 className="text-white text-2xl font-bold tracking-tight mb-1">
              {lang === "en"
                ? <><span>Welcome back, </span><span className={course.accentText}>{firstName}</span>!</>
                : <><span>αª╕αºìαª¼αª╛αªùαªñαª«, </span><span className={course.accentText}>{firstName}</span>!</>
              }
            </h2>
            <p className="text-slate-400 text-sm">
              {isEmpty
                ? (lang === "en" ? "No tests yet ΓÇö let's get started!" : "αªÅαªûαª¿αºï αªòαºïαª¿αºï αªƒαºçαª╕αºìαªƒ αª¿αºçαªç ΓÇö αª╢αºüαª░αºü αªòαª░αºüαª¿!")
                : (lang === "en"
                    ? `You've completed ${stats?.totalTests} test${(stats?.totalTests ?? 0) !== 1 ? "s" : ""}. Keep pushing!`
                    : `αªåαª¬αª¿αª┐ ${stats?.totalTests}αªƒαª┐ αªƒαºçαª╕αºìαªƒ αª╕αª«αºìαª¬αª¿αºìαª¿ αªòαª░αºçαª¢αºçαª¿αÑñ αªÜαª╛αª▓αª┐αª»αª╝αºç αª»αª╛αª¿!`)
              }
            </p>
          </div>
          <div className={`hidden sm:flex shrink-0 w-16 h-16 rounded-2xl ${course.accentBg} border ${course.accentBorder} items-center justify-center`}>
            <Keyboard className={`w-8 h-8 ${course.accentText}`} strokeWidth={1.5} />
          </div>
        </div>
      </div>

      {/* ΓöÇΓöÇ Stat cards ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
      <div className="grid grid-cols-2 sm:grid-cols-3 xl:grid-cols-6 gap-3">
        {statCards.map(({ label, value, icon: Icon, color, bg, border }) => (
          <div key={label} className={`rounded-2xl border ${border} ${bg} p-4 flex flex-col gap-2 backdrop-blur-sm`}>
            <div className="w-8 h-8 rounded-xl bg-slate-800 shadow-sm flex items-center justify-center">
              <Icon className={`w-4 h-4 ${color}`} strokeWidth={2} />
            </div>
            <div>
              <p className="text-slate-100 text-xl font-bold leading-none">{value}</p>
              <p className="text-slate-500 text-[11px] font-medium mt-0.5 uppercase tracking-wider">{label}</p>
            </div>
          </div>
        ))}
      </div>

      {/* ΓöÇΓöÇ Middle row ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
      <div className="grid grid-cols-1 lg:grid-cols-5 gap-4">

        {/* WPM Chart */}
        <div className="lg:col-span-3 rounded-2xl border border-slate-700/60 bg-slate-800/50 backdrop-blur-sm shadow-sm p-5">
