    </div>
  );

  if (!animated) return content;

  return (
    <motion.div
      animate={{ y: [0, -4, 0] }}
      transition={{ duration: 1.1, repeat: Infinity, ease: "easeInOut" }}
    >
      {content}
    </motion.div>
  );
}

