          </motion.div>
        </AnimatePresence>

        {/* ΓöÇΓöÇ Keyboard visualisation (below text, full width) ΓöÇΓöÇ */}
        {showKeyboard && (
          <AnimatePresence mode="wait" initial={false}>
            <motion.div
              key={pageIdx + "-kb"}
