              />
            </motion.div>
          </AnimatePresence>
        )}

        {/* ΓöÇΓöÇ Image panel (for non-keyboard pages) ΓöÇΓöÇ */}
        {!page.highlightKeys && page.image && !imageIsHand && (
          <AnimatePresence mode="wait" initial={false}>
            <motion.div
              key={pageIdx + "-img"}
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
