"use client";

import { useState, useEffect } from "react";
import { Keyboard } from "lucide-react";

// ΓöÇΓöÇ Demo texts for the typing animation ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const DEMO_LINES = [
  { text: "The quick brown fox jumps over the lazy dog.", lang: "English" },
  { text: "αªåαª«αª┐ αª¼αª╛αªéαª▓αª╛αª»αª╝ αªƒαª╛αªçαª¬αª┐αªé αª╢αª┐αªûαª¢αª┐ αªÅαª¼αªé αªªαºìαª░αºüαªñ αª╣αªÜαºìαª¢αª┐αÑñ", lang: "αª¼αª╛αªéαª▓αª╛" },
  { text: "Pack my box with five dozen liquor jugs.", lang: "English" },
  { text: "αª¬αºìαª░αªñαª┐αªªαª┐αª¿ αªàαª¿αºüαª╢αºÇαª▓αª¿ αªòαª░αª▓αºç αªªαªòαºìαª╖αªñαª╛ αª¼αª╛αªíαª╝αºçαÑñ", lang: "αª¼αª╛αªéαª▓αª╛" },
];

// ΓöÇΓöÇ Particle type ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
interface Particle {
  id: number; x: number; y: number;
  size: number; delay: number; dur: number; opacity: number;
}

// ΓöÇΓöÇ Keyboard rows ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const KB_ROWS = ["QWERTYUIOP", "ASDFGHJKL", "ZXCVBNM"];

export default function TypingPanel() {
  const [lineIdx, setLineIdx] = useState(0);
  const [typed, setTyped]     = useState(0);
  const [wpm, setWpm]         = useState(0);
  const [activeKey, setActiveKey] = useState("");
  const [particles, setParticles] = useState<Particle[]>([]);
  const [acc, setAcc] = useState(100);

  // Generate particles only on client to avoid hydration mismatch
  useEffect(() => {
    setParticles(
      Array.from({ length: 22 }, (_, i) => ({
        id: i,
        x: Math.random() * 100,
        y: Math.random() * 100,
        size: Math.random() * 3 + 1,
        delay: Math.random() * 6,
        dur: Math.random() * 8 + 6,
        opacity: 0.15 + Math.random() * 0.2,
      }))
    );
  }, []);

  const current = DEMO_LINES[lineIdx];

  // All keyboard chars flattened for random fallback highlight
  const ALL_KEYS = KB_ROWS.join("");

  // Typing animation
  useEffect(() => {
    if (typed >= current.text.length) {
      const t = setTimeout(() => {
        setLineIdx((i) => (i + 1) % DEMO_LINES.length);
        setTyped(0);
      }, 1600);
      return () => clearTimeout(t);
    }
    const delay = Math.random() * 60 + 30;
    const t = setTimeout(() => {
      setTyped((n) => n + 1);
      const ch = current.text[typed]?.toUpperCase() ?? "";
      // For Latin chars use actual key; for others (Bengali etc.) pick random key
      if (/[A-Z]/.test(ch)) {
        setActiveKey(ch);
      } else if (ch !== " ") {
        setActiveKey(ALL_KEYS[Math.floor(Math.random() * ALL_KEYS.length)]);
      } else {
        setActiveKey("");
      }
      // Simulate WPM
      setWpm((w) => Math.min(w + Math.floor(Math.random() * 3), 94));
    }, delay);
    return () => clearTimeout(t);
  }, [typed, lineIdx, current.text, ALL_KEYS]);

  // Clear active key highlight after short delay for realistic tap feel
  useEffect(() => {
    if (!activeKey) return;
    const t = setTimeout(() => setActiveKey(""), 130);
    return () => clearTimeout(t);
  }, [activeKey]);

  // Reset WPM on new line
  useEffect(() => {
    setWpm(Math.floor(Math.random() * 20) + 30);
  }, [lineIdx]);

  // Update accuracy client-side only (inside effect to avoid hydration mismatch)
  useEffect(() => {
    if (typed > 4) setAcc(97 + Math.floor(Math.random() * 3));
    else setAcc(100);
  }, [typed]);

  const progress = (typed / current.text.length) * 100;

  return (
    <div className="relative w-full h-full overflow-hidden flex flex-col items-center justify-center px-10 py-12">

      {/* ΓöÇΓöÇ Deep gradient background ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
      <div className="absolute inset-0 bg-gradient-to-br from-[#0f0c29] via-[#302b63] to-[#24243e]" />

      {/* ΓöÇΓöÇ Animated fluid blobs ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
      <div
        className="absolute top-[-10%] left-[10%] w-[420px] h-[420px] rounded-full opacity-40 animate-blob"
        style={{ background: "radial-gradient(circle, #7c3aed 0%, #4f46e5 40%, transparent 70%)", filter: "blur(60px)" }}
      />
      <div
        className="absolute bottom-[-5%] right-[5%] w-[380px] h-[380px] rounded-full opacity-35 animate-blob-delay"
        style={{ background: "radial-gradient(circle, #06b6d4 0%, #3b82f6 40%, transparent 70%)", filter: "blur(70px)" }}
      />
      <div
        className="absolute top-[40%] left-[-5%] w-[300px] h-[300px] rounded-full opacity-25 animate-blob-slow"
        style={{ background: "radial-gradient(circle, #ec4899 0%, #8b5cf6 50%, transparent 70%)", filter: "blur(80px)" }}
      />

      {/* ΓöÇΓöÇ Subtle grid overlay ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
      <div
        className="absolute inset-0 opacity-[0.04]"
        style={{
          backgroundImage: "linear-gradient(#fff 1px,transparent 1px),linear-gradient(90deg,#fff 1px,transparent 1px)",
          backgroundSize: "40px 40px",
        }}
      />

      {/* ΓöÇΓöÇ Floating particles (client-only, no SSR) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
      {particles.map((p) => (
        <div
          key={p.id}
          className="absolute rounded-full bg-white animate-float-particle"
          style={{
            left: `${p.x}%`,
            top: `${p.y}%`,
            width: p.size,
            height: p.size,
            opacity: p.opacity,
            animationDelay: `${p.delay}s`,
            animationDuration: `${p.dur}s`,
          }}
        />
      ))}

      {/* ΓöÇΓöÇ Content ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
