type StatusTone =
  | "success"
  | "warning"
  | "danger"
  | "info"
  | "neutral";

function formatMoney(minor?: number | null) {
  return ((minor ?? 0) / 100).toLocaleString("en-BD", {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  });
}

function formatDate(date?: string | null) {
  if (!date) {
    return "ΓÇö";
  }

  try {
    return format(
      new Date(date),
      "dd MMM yyyy, hh:mm a",
    );
  } catch {
    return "ΓÇö";
  }
}

function getStatusTone(status?: string | null): StatusTone {
  switch (status) {
    case "PAID":
    case "APPROVED":
    case "COMPLETED":
      return "success";

    case "PENDING":
    case "PENDING_PAYMENT":
    case "PENDING_MANUAL_REVIEW":
      return "warning";

    case "CANCELLED":
    case "REJECTED":
    case "FAILED":
    case "EXPIRED":
      return "danger";

    case "PROCESSING":
      return "info";

    default:
      return "neutral";
  }
}

function getStatusLabel(status?: string | null) {
  if (!status) {
    return "Unknown";
  }

  switch (status) {
    case "PAID":
      return "Paid";

    case "PENDING":
      return "Pending";

    case "PENDING_PAYMENT":
      return "Pending Payment";

    case "PENDING_MANUAL_REVIEW":
      return "Pending Review";

    case "APPROVED":
      return "Approved";

    case "REJECTED":
      return "Rejected";

    case "CANCELLED":
      return "Cancelled";

    case "FAILED":
      return "Failed";

    case "EXPIRED":
      return "Expired";

    case "PROCESSING":
      return "Processing";

    default:
      return status
        .replaceAll("_", " ")
        .toLowerCase()
        .replace(/\b\w/g, (character) =>
          character.toUpperCase(),
        );
  }
}

function StatusBadge({
  status,
}: {
  status?: string | null;
}) {
  const tone = getStatusTone(status);

  const toneClasses: Record<StatusTone, string> = {
    success:
      "border-emerald-200 bg-emerald-50 text-emerald-700",
    warning:
      "border-amber-200 bg-amber-50 text-amber-700",
    danger:
      "border-red-200 bg-red-50 text-red-700",
    info:
      "border-blue-200 bg-blue-50 text-blue-700",
    neutral:
