            <Clock className="w-6 h-6" />
          </div>
          <div>
            <p className="text-3xl font-bold text-slate-900 dark:text-white leading-tight">{pendingCount}</p>
            <p className="text-sm font-semibold text-slate-500 dark:text-slate-400">Pending</p>
          </div>
        </div>
