"use client";

import { Download, Printer, Plus } from "lucide-react";
import { Button } from "@/components/ui/button";
import Link from "next/link";
import { toast } from "sonner";

interface StudentData {
  student_id: string;
  name: string;
  phone: string;
  course: string;
  batch_name: string;
  total_course_fee: number;
  total_paid: number;
  current_due: number;
  status: string;
}

export function StudentsActions({ studentsData }: { studentsData: any }) {
  const handlePrint = () => {
    window.print();
  };

  const handleExport = () => {
    try {
      const headers = ["ID", "Name", "Phone", "Course", "Batch", "Total Fee", "Paid", "Due", "Status"];
      const rows = studentsData.map((s: any) => [
        s.student_id || "",
        `"${s.name}"`,
        s.phone,
        `"${s.course?.name || "N/A"}"`,
        `"${s.batch_name || "N/A"}"`,
        s.total_course_fee,
        s.total_paid,
        s.current_due,
        s.status
      ]);

      const csvContent = [
        headers.join(","),
        ...rows.map((row: any) => row.join(","))
      ].join("\n");

      const blob = new Blob([csvContent], { type: "text/csv;charset=utf-8;" });
      const url = URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.setAttribute("href", url);
      link.setAttribute("download", `students_export_${new Date().toISOString().split('T')[0]}.csv`);
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      toast.success("Students exported successfully!");
    } catch (e) {
      toast.error("Failed to export students.");
    }
  };

  return (
    <div className="flex flex-wrap items-center gap-2">
      <Button onClick={handlePrint} variant="outline" className="h-9 text-xs rounded-xl bg-white border-slate-200 text-slate-700 hover:bg-slate-50 font-semibold shadow-sm">
        <Printer className="w-3.5 h-3.5 mr-2" />
        Print
      </Button>
      <Button onClick={handleExport} variant="outline" className="h-9 text-xs rounded-xl bg-white border-slate-200 text-slate-700 hover:bg-slate-50 font-semibold shadow-sm">
        <Download className="w-3.5 h-3.5 mr-2" />
        Export
      </Button>
      <Button asChild className="h-9 text-xs rounded-xl bg-indigo-600 hover:bg-indigo-700 text-white font-bold shadow-sm shadow-indigo-200 px-4">
        <Link href="/admin/students/new">
          <Plus className="w-3.5 h-3.5 mr-2" />
          Add Student
        </Link>
      </Button>
    </div>
  );
}

"use client";

import { Input } from "@/components/ui/input";
import { Search } from "lucide-react";
import { useRouter, usePathname, useSearchParams } from "next/navigation";
import { useTransition, useState, useCallback } from "react";

export function StudentsSearch({ defaultValue }: { defaultValue?: string }) {
  const router = useRouter();
  const pathname = usePathname();
  const searchParams = useSearchParams();
  const [isPending, startTransition] = useTransition();
  const [value, setValue] = useState(defaultValue || "");

  // eslint-disable-next-line react-hooks/exhaustive-deps
  const debouncedSearch = useCallback(
    debounce((searchTerm: string) => {
      startTransition(() => {
        const params = new URLSearchParams(searchParams.toString());
        if (searchTerm) {
          params.set("search", searchTerm);
        } else {
          params.delete("search");
        }
        router.push(`${pathname}?${params.toString()}`);
      });
    }, 400),
    [searchParams, pathname, router]
  );

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    setValue(val);
    debouncedSearch(val);
  };

  return (
    <div className="relative w-full sm:max-w-xs">
      <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-slate-400" />
      <Input
        name="search"
        value={value}
        onChange={handleChange}
        placeholder="Search students..."
        autoComplete="off"
        className="pl-9 h-9 text-xs bg-white border-slate-200 rounded-xl shadow-sm focus-visible:border-indigo-500 focus-visible:ring-0 focus-visible:ring-offset-0"
      />
      {isPending && (
        <div className="absolute right-3 top-1/2 -translate-y-1/2">
          <div className="h-3.5 w-3.5 animate-spin rounded-full border-2 border-slate-200 border-t-indigo-500" />
        </div>
      )}
    </div>
  );
}

// Simple utility since we don't have a library
function debounce<T extends (...args: any[]) => void>(func: T, wait: number) {
  let timeout: ReturnType<typeof setTimeout>;
  return function (this: any, ...args: Parameters<T>) {
    clearTimeout(timeout);
    timeout = setTimeout(() => func.apply(this, args), wait);
  };
}

