import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";

/* =========================================================
   Types
========================================================= */

interface TrainingBatchFormProps {
  initialData?: TrainingBatch;
}

interface CourseTranslationRow {
  lang: string;
  name: string | null;
}

interface CourseRow {
  id: string;
  course_translations:
  | CourseTranslationRow[]
  | null;
}

interface CourseOption {
  id: string;
  name: string;
}

type BatchFormStatus =
  TrainingBatchValues["status"];

/* =========================================================
   Constants
========================================================= */

const BATCH_STATUSES: ReadonlyArray<{
  value: EditableTrainingBatchStatus;
  label: string;
}> = [
    {
      value: "draft",
      label: "Draft",
    },
    {
      value: "open",
      label: "Open (Admissions)",
    },
    {
      value: "full",
      label: "Full",
    },
    {
      value: "ongoing",
      label: "Ongoing (Classes)",
    },
    {
      value: "completed",
      label: "Completed",
    },
    {
      value: "cancelled",
      label: "Cancelled",
    },
  ];

const CAPACITY_REQUIRED_STATUSES:
  ReadonlyArray<BatchFormStatus> = [
    "open",
    "full",
    "ongoing",
  ];

/* =========================================================
   Helpers
========================================================= */

function getCourseName(
  course: CourseRow
): string {
  const translations =
    course.course_translations ?? [];

  const englishTranslation =
    translations.find(
      (translation) =>
        translation.lang === "en"
    );

  return (
    englishTranslation?.name ??
    translations[0]?.name ??
    "Unnamed Course"
  );
}

function mapCourseToOption(
  course: CourseRow
): CourseOption {
  return {
    id: course.id,
    name: getCourseName(course),
  };
}

function getErrorMessage(
  error: unknown
): string {
  if (error instanceof Error) {
    return error.message;
  }

  return "An unexpected error occurred";
}

function formatTime(value: string): string {
  if (!value) {
    return "--:--";
  }

  return value.slice(0, 5);
}

function isShiftCapacitySuccess(
  capacity: TrainingShiftCapacity | null
): capacity is Extract<
  TrainingShiftCapacity,
  { success: true }
> {
  return capacity?.success === true;
}

function getShiftCapacityErrorMessage(
  capacity: TrainingShiftCapacity
): string {
  if (capacity.success) {
    return "";
  }

  switch (capacity.error) {
    case "SHIFT_NOT_FOUND":
      return "αª¿αª┐αª░αºìαª¼αª╛αªÜαª┐αªñ αª╢αª┐αª½αªƒαªƒαª┐ αª¬αª╛αªôαºƒαª╛ αª»αª╛αºƒαª¿αª┐αÑñ";

    case "LAB_NOT_FOUND":
      return "αª╢αª┐αª½αªƒαºçαª░ αªƒαºìαª░αºçαª¿αª┐αªé αª▓αºìαª»αª╛αª¼ αª¬αª╛αªôαºƒαª╛ αª»αª╛αºƒαª¿αª┐αÑñ";

    case "SHIFT_CAPACITY_EXCEEDS_LAB":
      return "αª╢αª┐αª½αªƒαºçαª░ capacity αªƒαºìαª░αºçαª¿αª┐αªé αª▓αºìαª»αª╛αª¼αºçαª░ capacity αªÑαºçαªòαºç αª¼αºçαª╢αª┐αÑñ";

    default:
      return "αª╢αª┐αª½αªƒαºçαª░ capacity αª»αª╛αªÜαª╛αªç αªòαª░αª╛ αª»αª╛αºƒαª¿αª┐αÑñ";
  }
}

/* =========================================================
   Component
========================================================= */

export function TrainingBatchForm({
  initialData,
}: TrainingBatchFormProps) {
  const router = useRouter();

  const isArchived =
    initialData?.status === "archived";

  const [isSubmitting, setIsSubmitting] =
    useState(false);

  const [
    loadingDependencies,
    setLoadingDependencies,
  ] = useState(true);

  const [
    loadingCapacity,
    setLoadingCapacity,
  ] = useState(false);

  const [error, setError] = useState<
    string | null
  >(null);

  const [shifts, setShifts] = useState<
    TrainingShift[]
  >([]);

  const [courses, setCourses] = useState<
    CourseOption[]
  >([]);

  const [
    selectedShiftCapacity,
    setSelectedShiftCapacity,
  ] = useState<TrainingShiftCapacity | null>(
    null
  );

  const form = useForm<
    TrainingBatchFormInput,
    unknown,
    TrainingBatchValues
  >({
    resolver: zodResolver(trainingBatchSchema),

    defaultValues: {
      course_id:
        initialData?.course_id ?? "",

      shift_ids:
        initialData?.shifts?.map((s) => s.id) ?? [],

      name_en:
        initialData?.name_en ?? "",

      name_bn:
        initialData?.name_bn ?? "",

      session:
        initialData?.session ?? "",

      start_date:
        initialData?.start_date ?? "",

      end_date:
        initialData?.end_date ?? "",

      admission_deadline:
        initialData?.admission_deadline ?? "",

      orientation_date:
        initialData?.orientation_date ?? "",

      seat_limit:
        initialData?.seat_limit ?? null,

      waitlist_enabled:
        initialData?.waitlist_enabled ?? false,

      status:
        initialData?.status === "archived"
          ? "draft"
          : initialData?.status ?? "draft",

      sort_order:
        initialData?.sort_order ?? 0,
    },
  });

  const {
    register,
    handleSubmit,
    formState: {
      errors,
      isDirty,
    },
    setError: setFormError,
    setValue,
    watch,
  } = form;

  const watchedStatus = watch("status");

  const status: BatchFormStatus =
    watchedStatus ?? "draft";

  const courseId = watch("course_id");

  const shiftIds = watch("shift_ids") ?? [];

  const seatLimit = watch("seat_limit");

  const waitlistEnabled = watch(
    "waitlist_enabled"
  );

  const selectedShifts = useMemo(
    () =>
      shifts.filter((shift) =>
        shiftIds.includes(shift.id)
      ),
    [shiftIds, shifts]
  );

  const normalizedSeatLimit = useMemo(() => {
    if (
      seatLimit === "" ||
      seatLimit === null ||
      seatLimit === undefined
    ) {
      return null;
    }

    const numericValue = Number(seatLimit);

    return Number.isFinite(numericValue)
      ? numericValue
      : null;
  }, [seatLimit]);

  const combinedCapacity = useMemo(() => {
    return selectedShifts.reduce((total, shift) => {
      const shiftCap = shift.capacity_override ?? shift.lab?.manual_capacity_limit ?? shift.lab?.usable_computers ?? 0;
      return total + shiftCap;
    }, 0);
  }, [selectedShifts]);

  const effectiveBatchCapacity = useMemo(() => {
    if (normalizedSeatLimit !== null && combinedCapacity > 0) {
      return Math.min(normalizedSeatLimit, combinedCapacity);
    }
    if (normalizedSeatLimit !== null) {
      return normalizedSeatLimit;
    }
    return combinedCapacity;
  }, [normalizedSeatLimit, combinedCapacity]);

  const capacityIsRequired =
    CAPACITY_REQUIRED_STATUSES.includes(
      status
    );

  const hasCapacityConfiguration =
    effectiveBatchCapacity !== null &&
    effectiveBatchCapacity > 0;

  /* =========================================================
     Dependency Loading
  ========================================================= */

  useEffect(() => {
    let cancelled = false;

    async function loadDependencies() {
      setLoadingDependencies(true);
      setError(null);

      try {
        const supabase = createClient();

        const [
          shiftsResult,
          coursesResult,
        ] = await Promise.all([
          getTrainingShifts(),

          supabase
            .from("courses")
            .select(`
              id,
              course_translations (
                lang,
                name
              )
            `)
            .eq("status", "published"),
        ]);

        if (cancelled) {
          return;
        }

        if (shiftsResult.error) {
          throw new Error(
            shiftsResult.error
          );
        }

        const availableShifts =
          shiftsResult.data ?? [];

        setShifts(
          availableShifts.filter(
            (shift) =>
              shift.status === "active" ||
              initialData?.shifts?.some(
                (s) => s.id === shift.id
              )
          )
        );

        if (coursesResult.error) {
          throw new Error(
            coursesResult.error.message
          );
        }

        const courseRows =
          (coursesResult.data ??
            []) as CourseRow[];

        const mappedCourses =
          courseRows.map(mapCourseToOption);

        if (
          initialData?.course_id &&
          !mappedCourses.some(
            (course) =>
              course.id ===
              initialData.course_id
          )
        ) {
          const currentCourseResult =
            await supabase
              .from("courses")
              .select(`
                id,
                course_translations (
                  lang,
                  name
                )
              `)
              .eq(
                "id",
                initialData.course_id
              )
              .maybeSingle();

          if (currentCourseResult.error) {
            throw new Error(
              currentCourseResult.error.message
            );
          }

          if (currentCourseResult.data) {
            mappedCourses.push(
              mapCourseToOption(
                currentCourseResult.data as CourseRow
              )
            );
          }
        }

        setCourses(mappedCourses);
      } catch (loadError: unknown) {
        if (!cancelled) {
          setError(
            getErrorMessage(loadError)
          );
        }
      } finally {
        if (!cancelled) {
          setLoadingDependencies(false);
        }
      }
    }

    void loadDependencies();

    return () => {
      cancelled = true;
    };
  }, [
    initialData?.course_id,
    initialData?.shifts,
  ]);

  /* =========================================================
     Capacity Loading (Disabled - Handled server-side now)
  ========================================================= */
  useEffect(() => {
    // Multi-shift capacity is complex to preview live.
    // It is fully validated and combined during form submission.
    setLoadingCapacity(false);
  }, []);

  /* =========================================================
     Submit
  ========================================================= */

  const onSubmit: SubmitHandler<
    TrainingBatchValues
  > = async (data) => {
    if (isSubmitting || isArchived) {
      return;
    }

    setError(null);

    // Capacity checks are now strictly handled by the atomic save RPC.
    // We can rely on server validation to reject invalid capacities.

    const submittedEffectiveCapacity =
      data.seat_limit;

    if (
      CAPACITY_REQUIRED_STATUSES.includes(
        data.status
      ) &&
      data.shift_ids.length === 0
    ) {
      const message =
        "This batch status requires a valid capacity configuration.";

      setFormError("seat_limit", {
        type: "manual",
        message,
      });

      setError(message);

      return;
    }

    setIsSubmitting(true);

    try {
      const result =
        await saveTrainingBatch(
          initialData?.id ?? null,
          data
        );

      if (!result.success) {
        setError(result.error.message);

        return;
      }

      router.push(
        "/admin/training/batches"
      );

      router.refresh();
    } catch (submitError: unknown) {
      setError(
        getErrorMessage(submitError)
      );
    } finally {
      setIsSubmitting(false);
    }
  };

  /* =========================================================
     Archived Protection
  ========================================================= */

  if (isArchived) {
    return (
      <div className="max-w-5xl rounded-2xl border border-amber-200 bg-amber-50 p-6">
        <div className="flex items-start gap-4">
          <div className="rounded-xl bg-amber-100 p-3 text-amber-700">
            <AlertCircle className="h-6 w-6" />
          </div>

          <div className="flex-1">
            <h2 className="text-lg font-semibold text-amber-950">
              Archived batch
            </h2>

            <p className="mt-1 text-sm leading-6 text-amber-800">
              This batch is archived and cannot
              be edited from the standard batch
              form.
            </p>

            <Button
              type="button"
              variant="outline"
              className="mt-5"
              onClick={() =>
                router.push(
                  "/admin/training/batches"
                )
              }
            >
              Back to batches
            </Button>
          </div>
        </div>
      </div>
    );
  }

  /* =========================================================
     UI
  ========================================================= */

  return (
    <form
      onSubmit={handleSubmit(onSubmit)}
      className="max-w-5xl space-y-6"
    >
      {error && (
        <div className="flex items-start gap-3 rounded-xl border border-red-200 bg-red-50 p-4 text-red-800">
          <AlertCircle className="mt-0.5 h-5 w-5 shrink-0" />

          <p className="text-sm font-medium">
            {error}
          </p>
        </div>
      )}

      {/* Batch Assignment */}

      <section className="overflow-hidden rounded-2xl border border-slate-200 bg-white shadow-sm">
        <div className="border-b border-slate-100 px-6 py-5">
          <h2 className="text-base font-semibold text-slate-950">
            Batch Assignment
          </h2>

          <p className="mt-1 text-sm text-slate-500">
            Assign the course and training
            shift for this batch.
          </p>
        </div>

        <div className="grid grid-cols-1 gap-6 p-6 md:grid-cols-2">
          <div className="space-y-2">
            <Label>
              Course
              <span className="ml-1 text-red-500">
                *
              </span>
            </Label>

            <Select
              value={courseId}
              onValueChange={(value) =>
                setValue(
                  "course_id",
                  value,
                  {
                    shouldDirty: true,
                    shouldValidate: true,
                  }
                )
              }
              disabled={
                loadingDependencies ||
                Boolean(initialData)
              }
            >
              <SelectTrigger>
                <SelectValue
                  placeholder={
                    loadingDependencies
                      ? "Loading courses..."
                      : "Select a course"
                  }
                />
