function formatDate(value: string | null): string {
  if (!value) {
    return "TBA";
  }

  const date = new Date(value);

  if (Number.isNaN(date.getTime())) {
    return "Invalid date";
  }

  return new Intl.DateTimeFormat("en-US", {
    month: "short",
    day: "numeric",
    year: "numeric",
  }).format(date);
}

function formatTime(value: string | null): string {
  if (!value) {
    return "TBA";
  }

  return value.slice(0, 5);
}

function formatRelativeShare(value: number, total: number): string {
  if (total === 0) {
    return "0%";
  }

  return `${Math.round((value / total) * 100)}%`;
}

function csvEscape(value: string | number | null | undefined): string {
  const text = String(value ?? "");
  const escaped = text.replace(/"/g, "\"\"");
  return `"${escaped}"`;
}

function downloadCsv(items: TrainingBatchListItem[]) {
  const rows = [
    [
      "Batch",
      "Course",
      "Status",
      "Session",
      "Start Date",
      "End Date",
      "Primary Shift",
      "Lab",
      "Effective Capacity",
      "Occupied",
      "Available",
    ],
    ...items.map(({ batch, capacity }) => [
      batch.name_en,
      batch.course?.name ?? "",
      batch.status,
      batch.session ?? "",
      batch.start_date ?? "",
      batch.end_date ?? "",
      batch.shifts?.[0]?.name_en ?? "",
      batch.shifts?.[0]?.lab?.name ?? "",
      capacity?.effective_batch_capacity ?? "",
      capacity?.occupied ?? "",
      capacity?.available ?? "",
    ]),
  ];

  const csv = rows
    .map((row) => row.map((cell) => csvEscape(cell)).join(","))
    .join("\n");

  const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = "training-batches.csv";
  link.click();
  URL.revokeObjectURL(url);
}

