    courseFilter !== "all" ||
    sessionFilter !== "all" ||
    capacityFilter !== "all";

  function resetFilters() {
    setSearchQuery("");
    setStatusFilter("all");
    setCourseFilter("all");
    setSessionFilter("all");
    setCapacityFilter("all");
    setSortBy("newest");
  }

