}

function getInitialEditableStatus(
  shift?: TrainingShift
): EditableTrainingShiftStatus {
  if (!shift) {
    return "active";
  }

  if (
    shift.status === "active" ||
    shift.status === "inactive"
  ) {
    return shift.status;
  }

  throw new Error(
    "Archived shifts cannot be opened in the normal edit form."
  );
}

function getInitialSchedule(
  shift?: TrainingShift
): InitialScheduleState {
  if (!shift) {
    return {
      days: [],
      error: null,
    };
  }

  const parsedDays = parseTrainingDays(
    shift.class_days
  );

  if (!parsedDays) {
    return {
      days: [],
      error:
        "αªÅαªç αª╢αª┐αª½αªƒαºçαª░ αª╕αªéαª░αªòαºìαª╖αª┐αªñ αªòαºìαª▓αª╛αª╕ αªíαºç αªñαªÑαºìαª» αª╕αªáαª┐αªò αª¿αºƒαÑñ αªñαªÑαºìαª» αªáαª┐αªò αª¿αª╛ αªòαª░αª╛ αª¬αª░αºìαª»αª¿αºìαªñ αª╢αª┐αª½αªƒαªƒαª┐ αªÅαªíαª┐αªƒ αªòαª░αª╛ αª»αª╛αª¼αºç αª¿αª╛αÑñ",
    };
  }

  return {
    days: parsedDays,
    error: null,
  };
}

