        size: Math.random() * 3 + 1,
        delay: Math.random() * 6,
        dur: Math.random() * 8 + 6,
        opacity: 0.15 + Math.random() * 0.2,
      }))
    );
  }, []);

  const current = DEMO_LINES[lineIdx];

  // All keyboard chars flattened for random fallback highlight
  const ALL_KEYS = KB_ROWS.join("");

