      <div
        className="absolute top-[-10%] left-[10%] w-[420px] h-[420px] rounded-full opacity-30 dark:opacity-40 animate-blob"
        style={{ background: "radial-gradient(circle, #7c3aed 0%, #4f46e5 40%, transparent 70%)", filter: "blur(60px)" }}
      />
      <div
        className="absolute bottom-[-5%] right-[5%] w-[380px] h-[380px] rounded-full opacity-25 dark:opacity-35 animate-blob-delay"
        style={{ background: "radial-gradient(circle, #06b6d4 0%, #3b82f6 40%, transparent 70%)", filter: "blur(70px)" }}
      />
      <div
