function normalizeBoolean(value: unknown): boolean {
  return (
    value === true ||
    value === 'true' ||
    value === '1' ||
    value === 1
  );
}

function createSafeFileName(file: File) {
  const extension =
    file.name.split('.').pop()?.toLowerCase() || 'png';

  const randomPart = crypto.randomUUID();

  return `${Date.now()}_${randomPart}.${extension}`;
}

