          : `Maximum file size is ${isQrImage ? '5MB' : '2MB'
          }.`;
      }

      return null;
    },
    [isBn],
  );

  const uploadImage = useCallback(
    async (
      file: File,
      field: UploadField,
      folder: string,
    ) => {
      const validationError = validateImage(file, field);

      if (validationError) {
        toast.error(validationError);
        return;
      }

      setUploadingField(field);

