        }

        updateSetting(field, publicUrlData.publicUrl);

        toast.success(
          isBn
            ? 'αª¢αª¼αª┐ αª╕αª½αª▓αª¡αª╛αª¼αºç αªåαª¬αª▓αºïαªí αª╣αª»αª╝αºçαª¢αºç'
