            : `Failed to upload image: ${message}`,
        );
      } finally {
        setUploadingField(null);
      }
    },
    [
      isBn,
      supabase,
      updateSetting,
      validateImage,
    ],
  );

  const handleImageUpload = useCallback(
    (
      event: ChangeEvent<HTMLInputElement>,
