"use client";

import React, { useState, useEffect } from "react";

interface DobSelectorProps {
  value: string;
  onChange: (value: string) => void;
  error?: boolean;
}

export function DobSelector({ value, onChange, error }: DobSelectorProps) {
  const [day, setDay] = useState("");
  const [month, setMonth] = useState("");
  const [year, setYear] = useState("");

  useEffect(() => {
    if (value) {
      const [y, m, d] = value.split("-");
      if (y && m && d) {
        setYear(y);
        setMonth(m);
        setDay(d);
      }
    }
  }, [value]);

  const currentYear = new Date().getFullYear();
  const years = Array.from({ length: 80 }, (_, i) => currentYear - 5 - i);
  const months = [
    { value: "01", label: "January (01)" },
    { value: "02", label: "February (02)" },
    { value: "03", label: "March (03)" },
    { value: "04", label: "April (04)" },
    { value: "05", label: "May (05)" },
    { value: "06", label: "June (06)" },
    { value: "07", label: "July (07)" },
    { value: "08", label: "August (08)" },
    { value: "09", label: "September (09)" },
    { value: "10", label: "October (10)" },
    { value: "11", label: "November (11)" },
    { value: "12", label: "December (12)" },
  ];

  const getDaysInMonth = (y: string, m: string) => {
    if (!y || !m) return 31;
    return new Date(parseInt(y), parseInt(m), 0).getDate();
  };

  const daysInMonth = getDaysInMonth(year, month);
  const days = Array.from({ length: daysInMonth }, (_, i) => (i + 1).toString().padStart(2, "0"));

  const triggerChange = (newY: string, newM: string, newD: string) => {
    if (newY && newM && newD) {
      onChange(`${newY}-${newM}-${newD}`);
    } else {
      onChange(""); // Clear if incomplete
    }
  };

  const handleYearChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const y = e.target.value;
    setYear(y);
    let d = day;
    if (month && d) {
      const maxDays = getDaysInMonth(y, month);
      if (parseInt(d) > maxDays) d = maxDays.toString().padStart(2, "0");
    }
    setDay(d);
    triggerChange(y, month, d);
  };

  const handleMonthChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const m = e.target.value;
    setMonth(m);
    let d = day;
    if (year && d) {
      const maxDays = getDaysInMonth(year, m);
      if (parseInt(d) > maxDays) d = maxDays.toString().padStart(2, "0");
    }
    setDay(d);
    triggerChange(year, m, d);
  };

  const handleDayChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const d = e.target.value;
    setDay(d);
    triggerChange(year, month, d);
  };

  const selectClass = `flex-1 rounded-xl border ${error ? 'border-red-500' : 'border-slate-300 dark:border-slate-700'} bg-white dark:bg-slate-800 px-3 py-2.5 text-sm outline-none focus:ring-1 focus:ring-blue-400 transition-all text-slate-700 dark:text-slate-200 cursor-pointer appearance-none`;

  return (
    <div className="flex gap-2 w-full">
      <div className="relative flex-1">
        <select value={day} onChange={handleDayChange} className={selectClass} style={{ width: '100%' }}>
          <option value="" disabled>Day</option>
          {days.map((d) => (
            <option key={d} value={d}>
              {d}
            </option>
          ))}
        </select>
        <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-2 text-slate-400">
          <svg className="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"></path></svg>
        </div>
      </div>

      <div className="relative flex-[1.5]">
        <select value={month} onChange={handleMonthChange} className={selectClass} style={{ width: '100%' }}>
          <option value="" disabled>Month</option>
          {months.map((m) => (
            <option key={m.value} value={m.value}>
              {m.label}
            </option>
          ))}
        </select>
        <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-2 text-slate-400">
          <svg className="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"></path></svg>
        </div>
      </div>

      <div className="relative flex-1">
        <select value={year} onChange={handleYearChange} className={selectClass} style={{ width: '100%' }}>
          <option value="" disabled>Year</option>
          {years.map((y) => (
            <option key={y} value={y.toString()}>
              {y}
            </option>
          ))}
        </select>
        <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-2 text-slate-400">
          <svg className="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"></path></svg>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState, useCallback, useRef } from "react";
import { UploadCloud, X, File as FileIcon, CheckCircle2, Loader2 } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { getCloudinarySignature } from "@/lib/actions/cloudinary";

interface FileUploadProps {
  onUpload: (url: string) => void;
  onRemove: () => void;
  value?: string;
  label?: string;
  accept?: string;
  maxSizeMB?: number;
  folder?: string;
}

export default function FileUpload({
  onUpload,
  onRemove,
  value,
  label = "Upload File",
  accept = "image/*,application/pdf",
  maxSizeMB = 5,
  folder = "admissions"
}: FileUploadProps) {
  const [isDragging, setIsDragging] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [progress, setProgress] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFile = async (file: File) => {
    setError(null);
    if (file.size > maxSizeMB * 1024 * 1024) {
      setError(`File size must be less than ${maxSizeMB}MB`);
      return;
    }

    setIsUploading(true);
    setProgress(0);

    try {
      // 1. Get signature from Server Action
      const { signature, timestamp } = await getCloudinarySignature(folder);
      const cloudName = process.env.NEXT_PUBLIC_CLOUDINARY_CLOUD_NAME;
      const apiKey = process.env.NEXT_PUBLIC_CLOUDINARY_API_KEY;

      if (!cloudName || !apiKey) {
        throw new Error("Cloudinary environment variables are missing");
      }

      // 2. Prepare FormData
      const formData = new FormData();
      formData.append("file", file);
      formData.append("api_key", apiKey);
      formData.append("timestamp", timestamp.toString());
      formData.append("signature", signature);
      formData.append("folder", folder);

      // 3. Upload to Cloudinary using XMLHttpRequest for progress tracking
      const xhr = new XMLHttpRequest();
      xhr.open("POST", `https://api.cloudinary.com/v1_1/${cloudName}/auto/upload`);

      xhr.upload.onprogress = (e) => {
        if (e.lengthComputable) {
          const percentComplete = Math.round((e.loaded / e.total) * 100);
          setProgress(percentComplete);
        }
      };

      xhr.onload = () => {
        if (xhr.status === 200) {
          const response = JSON.parse(xhr.responseText);
          onUpload(response.secure_url);
          setIsUploading(false);
        } else {
          setError("Upload failed. Please try again.");
          setIsUploading(false);
        }
      };

      xhr.onerror = () => {
        setError("Network error occurred during upload.");
        setIsUploading(false);
      };

      xhr.send(formData);

    } catch (err: any) {
      setError(err.message || "An unexpected error occurred");
      setIsUploading(false);
    }
  };

  const onDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  }, []);

  const onDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  }, []);

  const onDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      handleFile(e.dataTransfer.files[0]);
    }
  }, []);

  return (
    <div className="w-full">
      {label && <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mb-2">{label}</label>}

      <AnimatePresence mode="wait">
        {value ? (
          <motion.div
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0, scale: 0.95 }}
            className="relative overflow-hidden rounded-2xl border border-slate-200 dark:border-slate-800 bg-slate-50 dark:bg-slate-900/50 p-4"
          >
            <div className="flex items-center gap-4">
              {value.match(/\.(jpeg|jpg|gif|png)$/i) || value.includes("image/upload") ? (
                <img src={value} alt="Preview" className="w-16 h-16 object-cover rounded-xl shadow-sm border border-slate-200 dark:border-slate-700" />
              ) : (
                <div className="w-16 h-16 rounded-xl bg-blue-100 dark:bg-blue-900/30 flex items-center justify-center border border-blue-200 dark:border-blue-800">
                  <FileIcon className="w-8 h-8 text-blue-500" />
                </div>
              )}
              <div className="flex-1 min-w-0">
                <p className="text-sm font-medium text-slate-900 dark:text-white truncate">Document Uploaded Successfully</p>
                <div className="flex items-center gap-1.5 mt-1 text-emerald-600 dark:text-emerald-400 text-xs font-semibold">
                  <CheckCircle2 className="w-3.5 h-3.5" />
                  Verified
                </div>
              </div>
              <button
                type="button"
                onClick={onRemove}
                className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-500/10 rounded-full transition-colors"
                title="Remove file"
              >
                <X className="w-5 h-5" />
              </button>
            </div>
          </motion.div>
        ) : (
          <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -10 }}
            onDragOver={onDragOver}
            onDragLeave={onDragLeave}
            onDrop={onDrop}
            onClick={() => !isUploading && fileInputRef.current?.click()}
            className={`
              relative cursor-pointer rounded-2xl border-2 border-dashed transition-all duration-200 p-8 text-center
              ${isDragging 
                ? "border-blue-500 bg-blue-50/50 dark:bg-blue-500/5" 
                : "border-slate-200 dark:border-slate-800 hover:border-slate-300 dark:hover:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-900/50"}
              ${isUploading ? "pointer-events-none opacity-80" : ""}
            `}
          >
            <input
              type="file"
              ref={fileInputRef}
              className="hidden"
              accept={accept}
              onChange={(e) => e.target.files && handleFile(e.target.files[0])}
            />

            <div className="flex flex-col items-center justify-center gap-3">
              {isUploading ? (
                <>
                  <div className="relative">
                    <Loader2 className="w-10 h-10 text-blue-500 animate-spin" />
                    <span className="absolute inset-0 flex items-center justify-center text-[10px] font-bold text-blue-600">{progress}%</span>
                  </div>
                  <p className="text-sm font-medium text-slate-600 dark:text-slate-400">Uploading securely...</p>
                </>
              ) : (
                <>
                  <div className={`p-3 rounded-full bg-slate-100 dark:bg-slate-800 transition-colors ${isDragging ? "bg-blue-100 dark:bg-blue-900/50 text-blue-600 dark:text-blue-400" : "text-slate-500 dark:text-slate-400"}`}>
                    <UploadCloud className="w-6 h-6" />
                  </div>
                  <div>
                    <p className="text-sm font-medium text-slate-900 dark:text-white">
                      <span className="text-blue-600 dark:text-blue-400">Click to upload</span> or drag and drop
                    </p>
                    <p className="text-xs text-slate-500 dark:text-slate-400 mt-1">
                      PDF, JPG, PNG or GIF (Max. {maxSizeMB}MB)
                    </p>
                  </div>
                </>
              )}
            </div>

            {error && (
              <div className="absolute bottom-3 inset-x-4">
                <p className="text-xs text-red-500 font-medium bg-red-50 dark:bg-red-500/10 py-1.5 px-3 rounded-lg inline-block">
                  {error}
                </p>
              </div>
            )}
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

"use client";

import { useTheme } from "next-themes";
import { useLang } from "@/context/GlobalLangContext";
import { Sun, Moon } from "lucide-react";
import { useEffect, useState } from "react";

export default function NavControls() {
  const { theme, setTheme } = useTheme();
  const { lang, setLang } = useLang();
  const [mounted, setMounted] = useState(false);

  useEffect(() => { setMounted(true); }, []);

  if (!mounted) return <div className="w-22 h-8 rounded-full" />;

  const isDark = theme === "dark";

  // Base pill style
  const pill =
    "flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-semibold transition-all duration-200 cursor-pointer select-none border";

  const themePill = isDark
    ? `${pill} border-slate-700 bg-slate-800/70 text-slate-200 hover:bg-slate-700`
    : `${pill} border-slate-200 bg-white text-slate-700 hover:bg-slate-100 shadow-sm`;

  const langPill = isDark
    ? `${pill} border-slate-700 bg-slate-800/70 text-slate-200 hover:bg-slate-700`
    : `${pill} border-slate-200 bg-white text-slate-700 hover:bg-slate-100 shadow-sm`;

  return (
    <div className="flex items-center gap-2">
      {/* Language toggle */}
      <button
        onClick={() => setLang(lang === "en" ? "bn" : "en")}
        title={lang === "en" ? "αª¼αª╛αªéαª▓αª╛αª»αª╝ αªªαºçαªûαºüαª¿" : "Switch to English"}
        className={langPill}
      >
        <span className="text-[11px] leading-none font-bn">
          {lang === "en" ? "αª¼αª╛αªéαª▓αª╛" : "EN"}
        </span>
      </button>

      {/* Theme toggle */}
      <button
        onClick={() => setTheme(isDark ? "light" : "dark")}
        title={isDark ? "Light mode" : "Dark mode"}
        className={themePill}
      >
        {isDark ? (
          <Sun size={13} strokeWidth={2.2} />
        ) : (
          <Moon size={13} strokeWidth={2.2} />
        )}
        <span className="text-[11px] leading-none">{isDark ? "Light" : "Dark"}</span>
      </button>
    </div>
  );
}

