export async function getOrderStats() {
  const supabase = getAdminClient();

  const [
    { count: totalOrders },
    { count: pendingReview },
    { data: todayRevenue },
  ] = await Promise.all([
    supabase.from("orders").select("*", { count: "exact", head: true }),
    supabase
      .from("manual_payment_reviews")
      .select("*", { count: "exact", head: true })
      .eq("status", "PENDING"),
    supabase
