export async function getTrainingBatches(): Promise<
  TrainingBatch[]
> {
  const supabase = await createClient();

  const { data, error } = await supabase
    .from("course_batches")
    .select(TRAINING_BATCH_SELECT)
    .order("created_at", {
      ascending: false,
    });

  if (error) {
    console.error(
      "Failed to fetch training batches:",
      error
