  const supabase = await createClient();

  const { data, error } = await supabase
    .from("course_batches")
    .select(TRAINING_BATCH_SELECT)
    .eq("id", id)
    .maybeSingle();

  if (error) {
    console.error(
      "Failed to fetch training batch:",
