/* =========================================================
   Batch Configuration Validation (Multi-Shift)
========================================================= */

async function validateBatchConfiguration(
  values: TrainingBatchValues,

  existingBatchId?: string
): Promise<BatchValidationResult> {
  let combinedShiftCapacity: number | null =
    null;

  if (values.shift_ids.length > 0) {
    let totalCapacity = 0;

    for (const shiftId of values.shift_ids) {
      const shiftResult =
        await validateSelectedShift(shiftId);

      if (!shiftResult.success) {
        return shiftResult;
      }

      totalCapacity +=
        shiftResult.data.effectiveCapacity;
    }

    combinedShiftCapacity = totalCapacity;
  }

  if (
    values.seat_limit !== null &&
    values.seat_limit !== undefined &&
    values.seat_limit <= 0
  ) {
    return {
      success: false,

      error: {
        code: "BATCH_SEAT_LIMIT_INVALID",

        message:
          "αª¼αºìαª»αª╛αªÜαºçαª░ αªåαª╕αª¿ αª╕αªéαªûαºìαª»αª╛ αªàαª¼αª╢αºìαª»αªç αºº αª¼αª╛ αªñαª╛αª░ αª¼αºçαª╢αª┐ αª╣αªñαºç αª╣αª¼αºçαÑñ",
      },
    };
  }

  if (
    combinedShiftCapacity !== null &&
    values.seat_limit !== null &&
    values.seat_limit !== undefined &&
    values.seat_limit > combinedShiftCapacity
  ) {
    return {
      success: false,

      error: {
        code:
          "BATCH_CAPACITY_EXCEEDS_SHIFT",

        message:
          `αª¼αºìαª»αª╛αªÜαºçαª░ αªåαª╕αª¿ αª╕αªéαªûαºìαª»αª╛ (${values.seat_limit}) ` +
          `αª╢αª┐αª½αªƒαªùαºüαª▓αºïαª░ αª«αºïαªƒ αªòαª╛αª░αºìαª»αªòαª░ αªºαª╛αª░αªúαªòαºìαª╖αª«αªñαª╛ (${combinedShiftCapacity}) ` +
          "αªÑαºçαªòαºç αª¼αºçαª╢αª┐ αª╣αªñαºç αª¬αª╛αª░αª¼αºç αª¿αª╛αÑñ",
      },
    };
  }

  const effectiveCapacity =
    values.seat_limit ?? combinedShiftCapacity;

  if (
    CAPACITY_RELEVANT_BATCH_STATUSES.includes(
      values.status
    ) &&
    (
      effectiveCapacity === null ||
      effectiveCapacity <= 0
    )
  ) {
    return {
      success: false,

      error: {
        code:
          "BATCH_CAPACITY_NOT_CONFIGURED",

        message:
          "Open, Full αª¼αª╛ Ongoing αª¼αºìαª»αª╛αªÜαºçαª░ αª£αª¿αºìαª» αªòαª«αª¬αªòαºìαª╖αºç αªÅαªòαªƒαª┐ αª╕αªòαºìαª░αª┐αª»αª╝ αª╢αª┐αª½αªƒ αªàαªÑαª¼αª╛ αª¼αºêαªº αªåαª╕αª¿ αª╕αºÇαª«αª╛ αª¿αª┐αª░αºìαªºαª╛αª░αªú αªòαª░αªñαºç αª╣αª¼αºçαÑñ",
      },
    };
  }

  if (existingBatchId) {
    const occupancyResult =
      await getBatchOccupiedSeats(
        existingBatchId
      );

    if (!occupancyResult.success) {
      return occupancyResult;
    }

    const occupied = occupancyResult.data;

    if (
      effectiveCapacity !== null &&
      effectiveCapacity < occupied
    ) {
      return {
        success: false,

        error: {
          code:
            "BATCH_CAPACITY_BELOW_OCCUPANCY",

